document.addEventListener('DOMContentLoaded', () => {
    const totalSalesEl = document.getElementById('totalSales');
    const newOrdersEl = document.getElementById('newOrders');
    const totalRevenueEl = document.getElementById('totalRevenue');
    const topProductsList = document.getElementById('topProductsList');
    const recentTransactionsList = document.getElementById('recentTransactionsList');
    const activeCustomersEl = document.getElementById('activeCustomers');
    const conversionRateEl = document.getElementById('conversionRate');
    const sparklineBars = document.querySelectorAll('.sparkline-bar');

    // Chart.js initialization
    const ctx = document.getElementById('liveSalesChart').getContext('2d');
    let liveSalesChart;
    const chartData = {
        labels: [], // Time labels
        datasets: [{
            label: 'Sales ($)',
            data: [], // Sales values
            borderColor: 'rgb(0, 230, 230)',
            backgroundColor: 'rgba(0, 230, 230, 0.2)',
            borderWidth: 2,
            pointRadius: 3,
            pointBackgroundColor: 'rgb(0, 230, 230)',
            tension: 0.4,
            fill: true
        }]
    };

    const chartOptions = {
        responsive: true,
        maintainAspectRatio: false,
        animation: {
            duration: 500, // General animation time
            easing: 'easeOutQuart'
        },
        scales: {
            x: {
                type: 'time',
                time: {
                    unit: 'minute',
                    tooltipFormat: 'HH:mm:ss',
                    displayFormats: {
                        minute: 'HH:mm'
                    }
                },
                ticks: {
                    color: 'rgba(224, 224, 224, 0.7)',
                    font: {
                        family: 'Roboto Mono'
                    }
                },
                grid: {
                    color: 'rgba(0, 230, 230, 0.1)'
                }
            },
            y: {
                beginAtZero: true,
                ticks: {
                    color: 'rgba(224, 224, 224, 0.7)',
                    callback: function(value) {
                        return '$' + value.toFixed(2);
                    },
                    font: {
                        family: 'Roboto Mono'
                    }
                },
                grid: {
                    color: 'rgba(0, 230, 230, 0.1)'
                }
            }
        },
        plugins: {
            legend: {
                display: true,
                labels: {
                    color: 'var(--text-color)',
                    font: {
                        family: 'Orbitron'
                    }
                }
            },
            tooltip: {
                enabled: true,
                mode: 'index',
                intersect: false,
                backgroundColor: 'rgba(26, 31, 46, 0.9)', // var(--card-bg) with opacity
                borderColor: 'rgba(0, 230, 230, 0.2)', // var(--border-color)
                borderWidth: 1,
                cornerRadius: 8,
                titleColor: 'var(--primary-color)',
                bodyColor: 'var(--text-color)',
                callbacks: {
                    label: function(context) {
                        let label = context.dataset.label || '';
                        if (label) {
                            label += ': ';
                        }
                        if (context.parsed.y !== null) {
                            label += new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(context.parsed.y);
                        }
                        return label;
                    }
                },
                titleFont: { family: 'Orbitron', size: 14, weight: 'bold' },
                bodyFont: { family: 'Roboto Mono', size: 12 },
                padding: 10
            }
        }
    };

    liveSalesChart = new Chart(ctx, {
        type: 'line',
        data: chartData,
        options: chartOptions
    });

    // --- Data Simulation ---
    let currentTotalSales = 125000;
    let currentNewOrders = 850;
    let currentTotalRevenue = 2300000;
    let currentActiveCustomers = 120;
    let currentConversionRate = 2.5;

    const products = [
        { name: 'NEXO Quantum Processor', sales: 12000, units: 150 },
        { name: 'Aetherial VR Headset', sales: 9500, units: 80 },
        { name: 'Chrono-Drive SSD 2TB', sales: 8100, units: 200 },
        { name: 'Neural Interface Keyboard', sales: 6700, units: 300 },
        { name: 'Plasma Energy Cell Pack', sales: 5200, units: 450 }
    ];

    const generateRandomTransaction = () => {
        const productNames = ['NEXO Quantum Processor', 'Aetherial VR Headset', 'Chrono-Drive SSD', 'Neural Interface Keyboard', 'Plasma Energy Cell Pack', 'Gravity Stabilizer', 'Sonic Emitter', 'Bio-Metric Scanner', 'Lux-Omni Drone', 'Cybernetic Arm Upgrade'];
        const randomProduct = productNames[Math.floor(Math.random() * productNames.length)];
        const amount = (Math.random() * (1500 - 50) + 50).toFixed(2);
        const now = new Date();
        const minutesAgo = Math.floor(Math.random() * 60);
        now.setMinutes(now.getMinutes() - minutesAgo);
        const time = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
        return { product: randomProduct, amount: parseFloat(amount), time: time };
    };

    let recentTransactions = Array.from({ length: 7 }, generateRandomTransaction).sort((a, b) => new Date('1970/01/01 ' + b.time) - new Date('1970/01/01 ' + a.time));

    const updateDashboard = () => {
        // Update main metrics
        totalSalesEl.textContent = `$${currentTotalSales.toFixed(2)}`;
        newOrdersEl.textContent = currentNewOrders.toLocaleString();
        totalRevenueEl.textContent = `$${currentTotalRevenue.toFixed(2)}`;
        activeCustomersEl.textContent = currentActiveCustomers.toLocaleString();
        conversionRateEl.textContent = `${currentConversionRate.toFixed(1)}%`;

        // Update Top Products
        topProductsList.innerHTML = '';
        products.sort((a, b) => b.sales - a.sales).slice(0, 5).forEach(p => {
            const li = document.createElement('li');
            li.innerHTML = `
                <span class="product-item-name">${p.name}</span>
                <span class="product-item-value">$${p.sales.toFixed(2)}</span>
            `;
            topProductsList.appendChild(li);
        });

        // Update Recent Transactions
        recentTransactionsList.innerHTML = '';
        recentTransactions.slice(0, 7).forEach(t => {
            const li = document.createElement('li');
            li.innerHTML = `
                <span class="transaction-item-details">${t.product} <span class="transaction-item-time">(${t.time})</span></span>
                <span class="transaction-item-amount">$${t.amount.toFixed(2)}</span>
            `;
            recentTransactionsList.appendChild(li);
        });

        // Update Sparkline (random heights for visual effect)
        sparklineBars.forEach(bar => {
            bar.style.height = `${Math.floor(Math.random() * 70) + 30}%`; // 30-100% height
        });
    };

    const simulateRealtimeData = () => {
        // Simulate new sale
        const newSaleAmount = Math.random() * 100 + 10; // $10 - $110
        currentTotalSales += newSaleAmount;
        currentTotalRevenue += newSaleAmount;

        // Simulate new order
        if (Math.random() < 0.7) { // 70% chance of a new order
            currentNewOrders += 1;
        }

        // Simulate customer activity
        currentActiveCustomers = Math.max(80, currentActiveCustomers + Math.floor(Math.random() * 5) - 2); // +- 2 customers
        currentConversionRate = Math.max(1.0, Math.min(5.0, currentConversionRate + (Math.random() * 0.2 - 0.1))); // +- 0.1 conversion rate

        // Update chart data
        const now = new Date();
        chartData.labels.push(now);
        chartData.datasets[0].data.push(newSaleAmount * 5); // Scale sales for chart visibility
        if (chartData.labels.length > 20) { // Keep last 20 data points
            chartData.labels.shift();
            chartData.datasets[0].data.shift();
        }
        liveSalesChart.update();

        // Simulate a recent transaction
        if (Math.random() < 0.9) { // High chance to add a new transaction
            const newTransaction = generateRandomTransaction();
            recentTransactions.unshift(newTransaction); // Add to the beginning
            recentTransactions = recentTransactions.slice(0, 10); // Keep max 10 transactions

            // Update top products based on simulated sales
            const productIndex = Math.floor(Math.random() * products.length);
            products[productIndex].sales += newTransaction.amount;
            products[productIndex].units += 1;
        }

        updateDashboard();
    };

    // Initial dashboard render
    updateDashboard();

    // Start real-time simulation
    setInterval(simulateRealtimeData, 2000); // Update every 2 seconds
});

