document.addEventListener('DOMContentLoaded', () => {
    const app = document.getElementById('app');
    const productGrid = document.getElementById('product-grid');
    const totalSalesElem = document.getElementById('total-sales');
    const newOrdersElem = document.getElementById('new-orders');
    const productsInStockElem = document.getElementById('products-in-stock');

    // Sample Data
    let products = [
        { id: 1, name: 'Quantum Processor X', price: 1299.99, stock: 75, image: 'https://via.placeholder.com/150/00e6e6/0a0a0d?text=CPU' },
        { id: 2, name: 'Neural Interface Headset', price: 749.50, stock: 30, image: 'https://via.placeholder.com/150/ff3366/0a0a0d?text=Headset' },
        { id: 3, name: 'Holographic Display Unit', price: 2999.00, stock: 15, image: 'https://via.placeholder.com/150/00e6e6/0a0a0d?text=Display' },
        { id: 4, name: 'Cybernetic Arm V2', price: 1850.25, stock: 5, image: 'https://via.placeholder.com/150/ff3366/0a0a0d?text=Arm' },
        { id: 5, name: 'AI Core Module', price: 999.00, stock: 50, image: 'https://via.placeholder.com/150/00e6e6/0a0a0d?text=AI+Core' },
        { id: 6, name: 'Fusion Power Cell', price: 450.00, stock: 120, image: 'https://via.placeholder.com/150/ff3366/0a0a0d?text=Power+Cell' },
        { id: 7, name: 'Advanced Sensor Array', price: 320.75, stock: 40, image: 'https://via.placeholder.com/150/00e6e6/0a0a0d?text=Sensor' },
        { id: 8, name: 'Robotic Assistant Drone', price: 1500.00, stock: 10, image: 'https://via.placeholder.com/150/ff3366/0a0a0d?text=Drone' },
    ];

    let salesData = {
        labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'],
        datasets: [{
            label: 'Monthly Sales ($)',
            data: [12000, 19000, 30000, 25000, 40000, 35000, 48000, 52000, 60000, 55000, 68000, 75000],
            backgroundColor: 'rgba(0, 230, 230, 0.4)',
            borderColor: 'var(--color-primary)',
            borderWidth: 2,
            tension: 0.4,
            pointBackgroundColor: 'var(--color-primary)',
            pointBorderColor: 'var(--color-bg-dark)',
            pointBorderWidth: 1,
            pointRadius: 4,
            pointHoverRadius: 6,
            fill: true
        }]
    };

    let categoryData = {
        labels: ['Processors', 'Peripherals', 'Displays', 'Robotics', 'AI', 'Power'],
        datasets: [{
            label: 'Product Categories',
            data: [25, 15, 10, 20, 18, 12], // Percentage distribution
            backgroundColor: [
                'rgba(0, 230, 230, 0.7)', // Primary
                'rgba(255, 51, 102, 0.7)', // Secondary
                'rgba(0, 153, 255, 0.7)', // Blue
                'rgba(153, 51, 255, 0.7)', // Purple
                'rgba(51, 255, 51, 0.7)', // Green
                'rgba(255, 153, 51, 0.7)'  // Orange
            ],
            borderColor: 'var(--color-bg-dark)',
            borderWidth: 1
        }]
    };

    let dashboardMetrics = {
        totalSales: 2150000,
        newOrders: 15,
        productsInStock: products.reduce((sum, p) => sum + p.stock, 0)
    };

    // Chart.js Configuration
    Chart.defaults.font.family = 'Poppins, sans-serif';
    Chart.defaults.color = 'var(--color-text-medium)';
    Chart.defaults.borderColor = 'rgba(255, 255, 255, 0.1)';

    const commonChartOptions = {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
            legend: {
                labels: {
                    color: 'var(--color-text-light)',
                    padding: 15
                }
            },
            datalabels: {
                color: 'var(--color-text-light)',
                font: {
                    weight: 'bold'
                },
                textShadowBlur: 5,
                textShadowColor: 'rgba(0, 0, 0, 0.5)'
            }
        },
        animation: {
            duration: 1500,
            easing: 'easeInOutQuart'
        }
    };

    // Initialize Charts
    const salesChartCtx = document.getElementById('salesChart').getContext('2d');
    const salesChart = new Chart(salesChartCtx, {
        type: 'line',
        data: salesData,
        options: {
            ...commonChartOptions,
            scales: {
                x: {
                    grid: {
                        color: 'rgba(255, 255, 255, 0.05)'
                    },
                    ticks: {
                        color: 'var(--color-text-medium)'
                    }
                },
                y: {
                    beginAtZero: true,
                    grid: {
                        color: 'rgba(255, 255, 255, 0.05)'
                    },
                    ticks: {
                        color: 'var(--color-text-medium)',
                        callback: function(value) {
                            return '$' + value.toLocaleString();
                        }
                    }
                }
            }
        },
        plugins: [ChartDataLabels]
    });

    const categoryChartCtx = document.getElementById('categoryChart').getContext('2d');
    const categoryChart = new Chart(categoryChartCtx, {
        type: 'doughnut',
        data: categoryData,
        options: {
            ...commonChartOptions,
            cutout: '70%',
            plugins: {
                ...commonChartOptions.plugins,
                datalabels: {
                    formatter: (value, ctx) => {
                        let sum = 0;
                        let dataArr = ctx.chart.data.datasets[0].data;
                        dataArr.map(data => {
                            sum += data;
                        });
                        let percentage = (value * 100 / sum).toFixed(1) + "%";
                        return percentage;
                    },
                    color: 'var(--color-text-light)',
                }
            }
        },
        plugins: [ChartDataLabels]
    });

    // Render Product Grid
    function renderProductGrid() {
        productGrid.innerHTML = '';
        products.forEach(product => {
            const productCard = document.createElement('div');
            productCard.classList.add('product-card', 'glass-effect');
            productCard.innerHTML = `
                <img src="${product.image}" alt="${product.name}" class="product-image">
                <h3 class="product-title">${product.name}</h3>
                <p class="product-price">$${product.price.toFixed(2)}</p>
                <p class="product-stock ${product.stock < 20 ? 'low' : ''}">Stock: ${product.stock}</p>
                <button class="btn add-to-cart" data-id="${product.id}">Add to Cart</button>
            `;
            productGrid.appendChild(productCard);
        });
    }

    // Update Dashboard Metrics
    function updateDashboardMetrics() {
        totalSalesElem.textContent = `$${dashboardMetrics.totalSales.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
        newOrdersElem.textContent = dashboardMetrics.newOrders;
        productsInStockElem.textContent = dashboardMetrics.productsInStock;
    }

    // Simulate Real-time Updates
    function simulateRealtimeUpdates() {
        // Update sales data
        const lastMonthSales = salesData.datasets[0].data[salesData.datasets[0].data.length - 1];
        const newMonthSales = lastMonthSales + Math.floor(Math.random() * 10000 - 5000); // +/- 5k
        salesData.datasets[0].data.push(Math.max(0, newMonthSales));
        salesData.labels.push('Next'); // Simplistic label for simulation
        // Keep only last 12 months for visual clarity
        if (salesData.datasets[0].data.length > 12) {
            salesData.datasets[0].data.shift();
            salesData.labels.shift();
        }
        salesChart.update();

        // Update product stock and overall stock
        let totalStockChange = 0;
        products.forEach(p => {
            const stockChange = Math.floor(Math.random() * 5) - 2; // -2, -1, 0, 1, 2
            p.stock = Math.max(0, p.stock - stockChange); // Simulate some sales and restocks
            totalStockChange -= stockChange; // Calculate overall change
        });
        renderProductGrid(); // Re-render products to show updated stock

        // Update dashboard metrics
        dashboardMetrics.totalSales += Math.floor(Math.random() * 5000);
        dashboardMetrics.newOrders += Math.floor(Math.random() * 3);
        dashboardMetrics.productsInStock += totalStockChange;

        updateDashboardMetrics();

        // Update category distribution slightly (less frequently)
        if (Math.random() < 0.3) { // Update ~30% of the time
            const categoryIndex = Math.floor(Math.random() * categoryData.datasets[0].data.length);
            const change = Math.random() < 0.5 ? 1 : -1;
            categoryData.datasets[0].data[categoryIndex] = Math.max(1, categoryData.datasets[0].data[categoryIndex] + change);
            categoryChart.update();
        }
    }

    // Initial renders
    renderProductGrid();
    updateDashboardMetrics();

    // Set up real-time update interval
    setInterval(simulateRealtimeUpdates, 5000); // Update every 5 seconds

    // Add to cart functionality (simulated)
    productGrid.addEventListener('click', (event) => {
        if (event.target.classList.contains('add-to-cart')) {
            const productId = parseInt(event.target.dataset.id);
            const product = products.find(p => p.id === productId);
            if (product && product.stock > 0) {
                product.stock--;
                dashboardMetrics.productsInStock--;
                dashboardMetrics.totalSales += product.price;
                dashboardMetrics.newOrders++;
                updateDashboardMetrics();
                renderProductGrid();
                alert(`${product.name} added to cart! (Stock: ${product.stock})`);
            } else if (product && product.stock === 0) {
                alert(`${product.name} is out of stock!`);
            }
        }
    });

    // Simple header animation on load
    const header = document.querySelector('.header');
    header.style.opacity = 0;
    header.style.transform = 'translateY(-20px)';
    setTimeout(() => {
        header.style.transition = 'opacity 0.8s ease-out, transform 0.8s ease-out';
        header.style.opacity = 1;
        header.style.transform = 'translateY(0)';
    }, 100); // Small delay to ensure CSS is parsed

    // Fade-in effect for main sections on load
    const sections = document.querySelectorAll('section');
    sections.forEach((section, index) => {
        section.style.opacity = 0;
        section.style.transform = 'translateY(20px)';
        setTimeout(() => {
            section.style.transition = 'opacity 0.8s ease-out, transform 0.8s ease-out';
            section.style.opacity = 1;
            section.style.transform = 'translateY(0)';
        }, 300 + index * 200); // Staggered fade-in
    });
});

